  ('diplomatic-9e854390-moex-00142', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列何國於本年7月主動召開相關高峰會，期解決蘇丹嚴重的內戰問題？', '["衣索比亞", "南非", "奈及利亞", "埃及"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
